class Solution:
    def maxCoins(self, nums):
        from functools import lru_cache
        vals = [1] + list(nums) + [1]
        @lru_cache(maxsize=None)
        def best(lo, hi):
            if lo > hi:
                return 0
            res = 0
            for k in range(lo, hi + 1):
                gain = vals[lo - 1] * vals[k] * vals[hi + 1]
                res = max(res, best(lo, k - 1) + best(k + 1, hi) + gain)
            return res
        return best(1, len(nums))

