class Solution:
    def maxCoins(self, nums):
        vals = [1] + list(nums) + [1]
        m = len(vals)
        dp = [[0] * m for _ in range(m)]
        for length in range(2, m):
            for lo in range(0, m - length):
                hi = lo + length
                best = 0
                for k in range(lo + 1, hi):
                    cand = dp[lo][k] + dp[k][hi] + vals[lo] * vals[k] * vals[hi]
                    if cand > best:
                        best = cand
                dp[lo][hi] = best
        return dp[0][m - 1]

solutions.javascript:
var maxCoins = function(nums) {
    const vals = [1, ...nums, 1];
    const m = vals.length;
    const dp = Array.from({ length: m }, () => new Array(m).fill(0));
    for (let length = 2; length < m; length++) {
        for (let lo = 0; lo + length < m; lo++) {
            const hi = lo + length;
            let best = 0;
            for (let k = lo + 1; k < hi; k++) {
                const cand = dp[lo][k] + dp[k][hi] + vals[lo] * vals[k] * vals[hi];
                if (cand > best) best = cand;
            }
            dp[lo][hi] = best;
        }
    }
    return dp[0][m - 1];
};
